mapper.update:
UPDATE accommodation_review
content = #{content}, rating = #{rating},
WHERE id = #{id}

mapper.select:
SELECT ar.id, ar.user_id as userId, ar.accommodation_id as accommodationId, ar.content, ar.rating, ar.create_time as createTime,
u.username, u.avatar
FROM accommodation_review ar
LEFT JOIN user u ON ar.user_id = u.id

    AND ar.accommodation_id = #{accommodationId}
    AND ar.user_id = #{userId}

ORDER BY ar.create_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM accommodation_review

    AND accommodation_id = #{accommodationId}
    AND user_id = #{userId}
